class KthLargest {
public:
    KthLargest(int k, vector<int>& nums) {
        maxHeap = new priority_queue<int>();
        for (int num : nums) {
            add(num);
        }
        kthLargest = k;
    }

    int add(int val) {
        maxHeap->push(val);
        if (maxHeap->size() > kthLargest) {
            maxHeap->pop();
        }
        return maxHeap->top();
    }
private:
    priority_queue<int> maxHeap;
    int kthLargest;
};
```
